fn fib(n: int) -> int {
    if n <= 1 { return n }
    return fib(n - 1) + fib(n - 2)
}
for i in 0..10 {
    println(fib(i))
}

let nums = [1, 2, 3, 4, 5]
let doubled = nums.map(|x| x * 2)
let evens = nums.filter(|x| x % 2 == 0)
let total = nums.fold(0, |acc, x| acc + x)
println(doubled, evens, total)

struct Point {
    x: float,
    y: float
}

impl Point {
    fn distance(self) -> float {
        return sqrt(self.x * self.x + self.y * self.y)
    }
}

let p = Point { x: 3.0, y: 4.0 }
println(p.distance())

enum Shape {
    Circle(float),
    Rect(float)
}

fn area(s) -> float {
    match s {
        Shape::Circle(r) -> 3.14159 * r * r,
        Shape::Rect(side) -> side * side
    }
}

println(area(Shape::Circle(5.0)))

fn describe(n: int) -> string {
    match n {
        0 -> "zero",
        1 -> "one",
        _ -> "other"
    }
}
println(describe(42))

