effect Logger {
    fn log(msg: str) -> int
}

let count = handle {
    let a = Logger.log("first")
    let b = Logger.log("second")
    a + b
} with {
    Logger.log(msg) => {
        println("LOG:", msg)
        resume(1)
    }
}
println("Total logs:", count)

fn factorial(n: int) -> int {
    if n <= 1 { return 1 }
    return n * factorial(n - 1)
}

proof factorial_correctness {
    assert factorial(0) == 1
    assert factorial(1) == 1
    assert factorial(5) == 120
    assert factorial(6) == 720
}

macro! double {
    ($x:expr) => {
        $x + $x
    }
}

let result = double!(21)
assert result == 42

comptime fn factorial(n: int) -> int {
    if n <= 1 { return 1 }
    return n * factorial(n - 1)
}

let table = comptime {
    let result = []
    for i in 1..7 {
        result = result.push(factorial(i))
    }
    result
}
println(table)

