trait Greetable {
    fn greet(self) -> string
}

struct Person {
    name: string
}

impl Greetable for Person {
    fn greet(self) -> string {
        return "Hello, " + self.name
    }
}

let p = Person { name: "Alice" }
let obj = dyn Greetable(p)
println(obj.greet())

